export function nextGeneration(livingCells: Cell[]): Cell[] {
  const aliveKeys = new Set(livingCells.map(cellKey));
  const candidates = new Map<string, Cell>();
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of livingCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const k = cellKey(neighbor);
      candidates.set(k, neighbor);
      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
    }
  }

  return Array.from(candidates).flatMap(([k, cell]) =>
    survives(neighborCounts.get(k)!, aliveKeys.has(k)) ? [cell] : []
  );
}

